/**
 * Main App Component
 * Root component for World Builder
 */

import React, { useEffect } from 'react';
import useWorldBuilderStore from './store/store.js';
import AreaBrowser from './components/AreaBrowser.jsx';
import RoomGrid from './components/RoomGrid.jsx';
import PropertyPanel from './components/PropertyPanel.jsx';
import Notifications from './components/Notifications.jsx';
import './App.css';

function App() {
  const { loadAreas } = useWorldBuilderStore();

  useEffect(() => {
    // Load areas on startup
    loadAreas();
  }, [loadAreas]);

  return (
    <div className="app">
      <header className="app-header">
        <h1>🗺️ ROM World Builder</h1>
        <p>Graphical Area & Room Editor for ROM 2.4</p>
      </header>

      <div className="app-container">
        <aside className="sidebar">
          <AreaBrowser />
        </aside>

        <main className="main-content">
          <RoomGrid />
        </main>

        <aside className="sidebar right-sidebar">
          <PropertyPanel />
        </aside>
      </div>

      <Notifications />
    </div>
  );
}

export default App;
